export default function Services() {
  const ref = useRef(null);
  const inView = useInView(ref, { once: true, margin: "-100px" });

  return (
    <section
      id="about"
      ref={ref}
      aria-labelledby="services-heading"
      className="relative py-16 md:py-24 px-6 bg-white"
    >
      <div className="max-w-6xl mx-auto">
        <motion.div
          variants={staggerContainer}
          initial="hidden"
          animate={inView ? "visible" : "hidden"}
          className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6"
        >
          {services.map((service) => (
            <motion.article
              key={service.title}
              variants={fadeUp}
              className="group relative bg-white cursor-default overflow-hidden pl-7 pr-10 py-10"
              style={{
                border: "1px solid #CCCCCC",
                borderRadius: "10px 10px 110px 10px",
              }}
              whileHover={{
                y: -6,
                boxShadow: "0 20px 60px rgba(0,0,0,0.10)",
                transition: { duration: 0.3, ease: "easeOut" },
              }}
            >
              {/* Subtle bg accent on hover */}
              <motion.div
                className="absolute inset-0 bg-orange-50"
                style={{ borderRadius: "10px 10px 110px 10px" }}
                initial={{ opacity: 0 }}
                whileHover={{ opacity: 1 }}
                transition={{ duration: 0.3 }}
              />

              <div className="relative z-10">
                {/* Icon circle: 71×71, icon 31×31 */}
                <div
                  className="flex items-center justify-center mb-6 bg-orange-500"
                  style={{ width: 71, height: 71, borderRadius: "50%" }}
                >
                  {service.icon}
                </div>

                <h3 className="text-xl font-semibold text-[#101010] mb-2 leading-snug">
                  {service.title}
                </h3>
                <p className="text-sm text-[#101010] leading-relaxed">
                  {service.description}
                </p>
              </div>
            </motion.article>
          ))}
        </motion.div>
      </div>
    </section>
  );
}
